    wrapped = f"<root>{body_xml}</root>".encode("utf-8")

    parser = etree.XMLParser(
        resolve_entities=False,
        no_network=True,
        load_dtd=False,
        huge_tree=False,
    )

    try:
        tree = etree.parse(BytesIO(wrapped), parser)
    except etree.XMLSyntaxError as e:
        raise ValueError(f"Malformed body XML: {e}") from e

    root = tree.getroot()
    operations = []
    for child in root:
        qname = etree.QName(child.tag)
        operations.append(qname.localname)

    return operations


